#include <iostream>
#include <stdexcept>

long long checked_divide(long long numerator, long long denominator) {
    if (denominator == 0) throw std::invalid_argument("zero divisor");
    return numerator / denominator;
}

int main() {
    long long numerator{}, denominator{};
    if (!(std::cin >> numerator >> denominator)) return 1;
    try { std::cout << checked_divide(numerator, denominator) << '\n'; }
    catch (const std::invalid_argument&) { std::cout << "division-by-zero\n"; }
}
